import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { BrowserRouter, Routes, Route, Link, useNavigate, useParams, Outlet, useLocation } from 'react-router-dom';
import { LogIn, UserPlus, Building, PlusCircle, Home, MapPin, Search, Edit, Trash2, MessageSquare, Heart, LayoutDashboard, Bell, ArrowLeft, Bed, Bath, Send } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, RadialBarChart, RadialBar } from 'recharts';
import toast, { Toaster } from 'react-hot-toast';
import axios from 'axios';

// --- API & WEBSOCKET CONFIGURATION ---
const API_URL = 'http://localhost:3001';

export const WEBSOCKET_URL = API_URL.replace(/^http/, 'ws'); // Converts http:// to ws://

const api = axios.create({
  baseURL: API_URL,
});

// Request Interceptor: Attaches the JWT token to every outgoing request
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers['Authorization'] = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Response Interceptor: Handles expired tokens and authentication errors globally
api.interceptors.response.use(
  (response) => response, // Pass through successful responses
  (error) => {
    // Check if the error is due to an invalid/expired token (401 or 403)
    if (error.response && (error.response.status === 401 || error.response.status === 403)) {
      // Clear user data from storage
      localStorage.removeItem('currentUser');
      localStorage.removeItem('token');
      
      // Redirect to the login page. This will cause the app to re-initialize.
      if (window.location.pathname !== '/login') {
        toast.error("Your session has expired. Please log in again.");
        window.location.href = '/login';
      }
    }
    return Promise.reject(error);
  }
);


// --- AUTHENTICATION CONTEXT ---
const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [currentUser, setCurrentUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        try {
            const storedUser = localStorage.getItem("currentUser");
            if (storedUser) setCurrentUser(JSON.parse(storedUser));
        } catch (error) {
            console.error("Failed to parse stored user", error);
            localStorage.clear();
        }
        setLoading(false);
    }, []);

    useEffect(() => {
        if (currentUser) {
            localStorage.setItem("currentUser", JSON.stringify(currentUser));
        } else {
            localStorage.removeItem("currentUser");
            localStorage.removeItem("token");
        }
    }, [currentUser]);

    const logout = useCallback(() => setCurrentUser(null), []);

    return (
        <AuthContext.Provider value={{ currentUser, setCurrentUser, logout, loading }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);

// --- DASHBOARD LAYOUT & COMPONENTS ---

const DashboardLayout = () => {
    const { currentUser, loading } = useAuth();
    const navigate = useNavigate();

    useEffect(() => {
        // Redirect to login only after the initial user check is complete
        if (!loading && !currentUser) {
            navigate('/login');
        }
    }, [currentUser, loading, navigate]);

    if (loading || !currentUser) {
        return <div className="h-screen w-full flex items-center justify-center bg-slate-900 text-white">Loading...</div>; // Or a spinner component
    }

    return (
        <div className="flex h-screen bg-slate-900 text-slate-100 font-sans">
            <Sidebar />
            <div className="flex-1 flex flex-col overflow-hidden">
                <Header />
                <main className="flex-1 overflow-x-hidden overflow-y-auto bg-slate-900 p-8">
                    <Outlet />
                </main>
            </div>
        </div>
    );
};

const Sidebar = () => {
    const location = useLocation();
    const { currentUser, logout } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };
    
    const navItems = [
        { icon: LayoutDashboard, label: "Dashboard", path: "/" },
        { icon: Building, label: "Properties", path: "/properties" },
        { icon: MessageSquare, label: "Messages", path: "/messages" },
        { icon: Heart, label: "Favorites", path: "/favorites" },
    ];

    return (
        <aside className="w-64 bg-slate-900 p-6 flex flex-col border-r border-slate-800">
            <div className="flex items-center space-x-2 mb-10">
                <Building className="h-8 w-8 text-indigo-400" />
                <span className="text-white text-2xl font-bold">Housing Hub</span>
            </div>
            <nav className="flex-1">
                <ul>
                    {navItems.map(item => (
                        <li key={item.label}>
                            <Link to={item.path} className={`flex items-center gap-3 px-4 py-3 my-2 rounded-lg transition-colors ${location.pathname.startsWith(item.path) && item.path !== '/' || location.pathname === '/' && item.path === '/' ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                                <item.icon size={20} />
                                <span>{item.label}</span>
                            </Link>
                        </li>
                    ))}
                </ul>
            </nav>
            <div className="mt-auto">
                {currentUser && (
                    <div className="flex items-center gap-3 p-3 bg-slate-800 rounded-lg mb-4">
                        <img className="h-10 w-10 rounded-full object-cover" src={`https://placehold.co/100x100/1e293b/a78bfa?text=${currentUser.email.charAt(0).toUpperCase()}`} alt="User Avatar" />
                        <div>
                            <p className="font-semibold text-white truncate">{currentUser.email}</p>
                            <p className="text-sm text-slate-400 capitalize">{currentUser.userType}</p>
                        </div>
                    </div>
                )}
                 <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 text-slate-400 hover:bg-red-900/50 hover:text-white py-2 rounded-lg transition-colors">
                    <LogIn size={16} />
                    <span>Logout</span>
                </button>
            </div>
        </aside>
    );
};

const Header = () => {
    const location = useLocation();
    const getTitle = () => {
        if (location.pathname.startsWith('/properties/')) return 'Property Details';
        if (location.pathname.startsWith('/edit-property/')) return 'Edit Property';
        if (location.pathname.startsWith('/messages')) return 'Your Messages';
        switch (location.pathname) {
            case '/': return 'Dashboard';
            case '/properties': return 'Property Listings';
            case '/add-property': return 'Add New Property';
            case '/favorites': return 'My Favorites';
            default: return 'Housing Hub';
        }
    };
    
    return (
        <header className="bg-slate-900/80 backdrop-blur-md p-4 flex justify-between items-center border-b border-slate-800 flex-shrink-0">
            <div>
                <h1 className="text-2xl font-bold text-white">{getTitle()}</h1>
            </div>
            <div className="flex items-center gap-4">
                <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                    <input type="text" placeholder="Search..." className="bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500" />
                </div>
                <button className="p-2 bg-slate-800 rounded-lg border border-slate-700 hover:bg-slate-700">
                    <Bell size={20} className="text-slate-300" />
                </button>
                {useAuth().currentUser?.userType === 'landlord' && (
                    <Link to="/add-property" className="bg-indigo-600 text-white font-bold py-2 px-4 rounded-lg flex items-center gap-2 hover:bg-indigo-500 transition-colors">
                        <PlusCircle size={20} />
                        <span>New Property</span>
                    </Link>
                )}
            </div>
        </header>
    );
};


// --- PAGE COMPONENTS (VIEWS) ---

const DashboardView = () => {
    const { currentUser } = useAuth();
    const [stats, setStats] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        if (currentUser && currentUser.userType === 'landlord') {
            const fetchStats = async () => {
                setLoading(true);
                try {
                    const { data } = await api.get('/api/dashboard/stats');
                    setStats(data);
                    setError('');
                } catch (err) {
                    // The interceptor will handle auth errors, but we still catch others.
                    if (err.response?.status !== 401 && err.response?.status !== 403) {
                       setError('Failed to load dashboard data. Please try again later.');
                    }
                    console.error(err);
                } finally {
                    setLoading(false);
                }
            };
            fetchStats();
        } else {
            setLoading(false);
        }
    }, [currentUser]);

    // Recharts data needs to be memoized or defined inside the render
    const propertyViewsData = stats?.properties?.map(p => ({
        name: p.title.substring(0, 15) + (p.title.length > 15 ? '...' : ''),
        Views: p.view_count,
    })) || [];
    
    const favoritesData = [{ 
        name: 'Favorites', 
        value: stats?.summary?.totalFavorites || 0,
        fill: '#f43f5e' // Rose color for favorites
    }];

    // Loading and Error States
    if (loading) return <div className="text-center text-slate-400">Loading dashboard...</div>;
    if (error) return <div className="text-center text-red-400">{error}</div>;

    // --- LANDLORD VIEW ---
    if (currentUser && currentUser.userType === 'landlord' && stats) {
        return (
            <div className="space-y-8">
                {/* Stat Cards */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 flex items-center gap-4">
                        <div className="p-3 bg-indigo-600/20 rounded-lg"><Building size={28} className="text-indigo-400" /></div>
                        <div>
                            <p className="text-3xl font-bold text-white">{stats.summary.totalProperties}</p>
                            <p className="text-slate-400">Total Properties</p>
                        </div>
                    </div>
                    <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 flex items-center gap-4">
                         <div className="p-3 bg-sky-600/20 rounded-lg"><Search size={28} className="text-sky-400" /></div>
                        <div>
                            <p className="text-3xl font-bold text-white">{stats.summary.totalViews}</p>
                            <p className="text-slate-400">Total Views</p>
                        </div>
                    </div>
                     <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 flex items-center gap-4">
                         <div className="p-3 bg-rose-600/20 rounded-lg"><Heart size={28} className="text-rose-400" /></div>
                        <div>
                            <p className="text-3xl font-bold text-white">{stats.summary.totalFavorites}</p>
                            <p className="text-slate-400">Total Favorites</p>
                        </div>
                    </div>
                    <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 flex items-center gap-4">
                        <div className="p-3 bg-emerald-600/20 rounded-lg"><MessageSquare size={28} className="text-emerald-400" /></div>
                        <div>
                            <p className="text-3xl font-bold text-white">{stats.summary.totalConversations}</p>
                            <p className="text-slate-400">Conversations</p>
                        </div>
                    </div>
                </div>

                {/* Charts */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    <div className="lg:col-span-2 bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
                        <h2 className="text-xl font-bold text-white mb-4">Property Views Analytics</h2>
                        {propertyViewsData.length > 0 ? (
                            <ResponsiveContainer width="100%" height={250}>
                                <BarChart data={propertyViewsData} margin={{ top: 5, right: 20, left: -10, bottom: 5 }}>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
                                    <XAxis dataKey="name" stroke="#9ca3af" />
                                    <YAxis stroke="#9ca3af" />
                                    <Tooltip contentStyle={{ backgroundColor: '#1f2937', border: '1px solid #374151' }} cursor={{ fill: 'rgba(129, 140, 248, 0.1)' }}/>
                                    <Bar dataKey="Views" fill="#818cf8" />
                                </BarChart>
                            </ResponsiveContainer>
                        ) : (
                            <div className="h-[250px] flex items-center justify-center text-slate-500">Add a property to see view analytics.</div>
                        )}
                    </div>
                    <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 flex flex-col items-center justify-center">
                        <h2 className="text-xl font-bold text-white mb-4">Total Favorites</h2>
                        <ResponsiveContainer width="100%" height={250}>
                             <RadialBarChart innerRadius="70%" outerRadius="90%" data={favoritesData} startAngle={90} endAngle={-270} barSize={30}>
                                <RadialBar minAngle={15} dataKey='value' cornerRadius={15} />
                                <text x="50%" y="50%" textAnchor="middle" dominantBaseline="middle" className="text-4xl font-bold fill-white">
                                    {stats.summary.totalFavorites}
                                </text>
                            </RadialBarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>
        );
    }

    // --- STUDENT VIEW ---
    if (currentUser) {
        return (
            <div className="bg-slate-800/50 p-8 rounded-2xl border border-slate-700 text-center">
                <h1 className="text-3xl font-bold text-white mb-2">Welcome to Housing Hub, {currentUser.email}!</h1>
                <p className="text-slate-300 text-lg mb-6">Your central place for finding the perfect student accommodation.</p>
                <Link to="/properties" className="bg-indigo-600 text-white font-bold py-3 px-6 rounded-lg hover:bg-indigo-500 transition-colors">
                    Browse Properties
                </Link>
            </div>
        );
    }

    return null;
};

const PropertiesView = () => {
    const { currentUser } = useAuth();
    const navigate = useNavigate();
    const [properties, setProperties] = useState([]);
    const [favorites, setFavorites] = useState(new Set());
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    const fetchData = useCallback(async () => {
        if (!currentUser) return;
        setLoading(true);
        try {
            const [propsResponse, favsResponse] = await Promise.all([
                api.get('/api/properties'),
                currentUser.userType === 'student' ? api.get('/api/favorites') : Promise.resolve({ data: [] })
            ]);
            setProperties(propsResponse.data);
            setFavorites(new Set(favsResponse.data.map(fav => fav._id)));
        } catch (err) {
            if (err.response?.status !== 401 && err.response?.status !== 403) {
               setError('Failed to fetch data.');
            }
        } finally {
            setLoading(false);
        }
    }, [currentUser]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleDelete = async (propertyId, e) => {
        e.stopPropagation();
        e.preventDefault();
        if (window.confirm('Are you sure you want to delete this property?')) {
            try {
                await api.delete(`/api/properties/${propertyId}`);
                fetchData();
                toast.success('Property deleted successfully.');
            } catch (err) {
                toast.error('Failed to delete property.');
            }
        }
    };
    
    const handleEdit = (propertyId, e) => {
        e.stopPropagation();
        e.preventDefault();
        navigate(`/edit-property/${propertyId}`);
    };

    const handleToggleFavorite = async (propertyId, e) => {
        e.stopPropagation();
        e.preventDefault();
        const newFavorites = new Set(favorites);
        try {
            if (favorites.has(propertyId)) {
                await api.delete(`/api/favorites/${propertyId}`);
                newFavorites.delete(propertyId);
                toast.error('Property removed from favorites.');
            } else {
                await api.post('/api/favorites', { property_id: propertyId });
                newFavorites.add(propertyId);
                toast.success('Property added to your favorites!');
            }
            setFavorites(newFavorites);
        } catch (err) {
            toast.error('Failed to update favorites.');
        }
    };

    if (loading) return <div className="text-center text-slate-400">Loading properties...</div>;
    if (error) return <div className="text-center text-red-400">{error}</div>;

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {properties.map(prop => (
                <Link to={`/properties/${prop._id}`} key={prop._id} className="bg-slate-800/50 rounded-2xl shadow-lg border border-slate-700 overflow-hidden group hover:border-indigo-500/50 transition-all duration-300">
                    <div className="overflow-hidden h-56">
                      <img src={prop.image_url || 'https://placehold.co/400x300/1e293b/94a3b8?text=No+Image'} alt={prop.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"/>
                    </div>
                    <div className="p-6">
                        <h3 className="text-xl font-bold text-white mb-2 truncate">{prop.title}</h3>
                        <p className="text-slate-400 text-sm mb-4 flex items-center gap-2"><MapPin size={16} />{prop.address}, {prop.city}</p>
                        <div className="flex justify-between items-center">
                            <p className="text-indigo-400 text-2xl font-bold">₹{prop.price.toLocaleString()}<span className="text-sm text-slate-400 font-normal">/mo</span></p>
                            {currentUser.userType === 'landlord' && currentUser.uid === prop.landlord_id && (
                                <div className="flex items-center gap-2">
                                    <button onClick={(e) => handleEdit(prop._id, e)} className="p-2 bg-slate-700 rounded-md hover:bg-indigo-600 transition-colors"><Edit size={16} /></button>
                                    <button onClick={(e) => handleDelete(prop._id, e)} className="p-2 bg-slate-700 rounded-md hover:bg-red-600 transition-colors"><Trash2 size={16} /></button>
                                </div>
                            )}
                             {currentUser.userType === 'student' && (
                                <button onClick={(e) => handleToggleFavorite(prop._id, e)} className={`p-2 rounded-md transition-colors ${favorites.has(prop._id) ? 'bg-pink-600 text-white' : 'bg-slate-700 hover:bg-pink-600/50'}`}>
                                    <Heart size={16} />
                                </button>
                             )}
                        </div>
                    </div>
                </Link>
            ))}
        </div>
    );
};

const AddPropertyView = () => {
